SELECT sd.id, sd.parent_id, sd.dept_name, sd.dept_code, sd.data_status, sd.dept_order, sd.create_time FROM sys_dept sd WHERE sd.enabled = '1'
AND sd.dept_name LIKE CONCAT(#{req.deptName},'%')
AND sd.data_status = #{req.dataStatus}
${req.dataScopeSql}
ORDER BY sd.dept_order, sd.id

SELECT sd.id, sd.parent_id, sd.dept_name, sd.dept_level, sd.data_status FROM sys_dept sd WHERE sd.enabled = '1'
${query.dataScopeSql}
ORDER BY sd.dept_order, sd.id
